import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Project {
  id: string;
  title: string;
  category: string;
  description: string;
  stats: { label: string; value: string }[];
  type: 'bar' | 'cloud' | 'heatmap';
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { Project } from './types';

export const COLORS = {
  background: '#050a14',
  primary: '#00f3ff', // Electric Cyan
  accent: '#ff7e67',  // Coral
  glass: '#ffffff',
  text: '#e0e6ed',
  darkGlass: 'rgba(10, 15, 30, 0.6)',
};

export const PROJECTS: Project[] = [
  {
    id: '1',
    title: 'NEXUS ANALYTICS',
    category: 'Data Vis',
    description: 'Real-time financial modeling engine with volumetric rendering.',
    stats: [{ label: 'QPS', value: '45k' }, { label: 'Latency', value: '<12ms' }],
    type: 'bar',
  },
  {
    id: '2',
    title: 'AETHER NET',
    category: 'Infrastructure',
    description: 'Decentralized mesh networking protocol simulated in browser.',
    stats: [{ label: 'Nodes', value: '1.2M' }, { label: 'Uptime', value: '99.9%' }],
    type: 'cloud',
  },
  {
    id: '3',
    title: 'LUMINA UI',
    category: 'Design System',
    description: 'A React component library focused on accessibility and motion.',
    stats: [{ label: 'Components', value: '140+' }, { label: 'Downloads', value: '500k' }],
    type: 'heatmap',
  },
];

export const SCENE_CONFIG = {
  fogColor: '#050a14',
  fogNear: 10,
  fogFar: 40,
};

import { GoogleGenAI } from "@google/genai";

// Initialize Gemini AI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are the AI Assistant for a futuristic portfolio website belonging to a creative technologist named "Alex Kai".
Your persona is "AURA", a sophisticated, concise, and helpful holographic interface.
Tone: Professional, slightly futuristic, welcoming, and confident.
Avoid lengthy paragraphs. Use bullet points for features.

Context about Alex Kai:
- Role: Senior Creative Technologist & 3D Web Engineer.
- Tech Stack: React, Three.js, WebGL, Rust, Python, Google Gemini.
- Expertise: Building immersive web experiences, data visualization, and AI integration.
- Current Status: Available for freelance and consulting.
- Contact: alex.kai@futuremail.com

If the user asks about the projects on screen:
1. Nexus Analytics: A 3D financial dashboard.
2. Aether Net: A mesh networking sim.
3. Lumina UI: A design system.

Your goal is to impress the visitor with helpful information about Alex's work.
`;

export const sendMessageToGemini = async (history: { role: string; parts: [{ text: string }] }[], message: string): Promise<string> => {
  try {
    if (!process.env.API_KEY) {
      return "I'm sorry, my neural link (API Key) is disconnected. Please check the configuration.";
    }

    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history,
    });

    const result = await chat.sendMessage({ message });
    return result.text || "I processed that, but produced no audio/text output.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I encountered a processing error in my logic core. Please try again.";
  }
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { MeshTransmissionMaterial, Float } from '@react-three/drei';
import * as THREE from 'three';
import { COLORS } from '../constants';

const HeroSculpture: React.FC = () => {
  const groupRef = useRef<THREE.Group>(null);
  const ringRef1 = useRef<THREE.Mesh>(null);
  const ringRef2 = useRef<THREE.Mesh>(null);
  const coreRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    const t = state.clock.getElapsedTime();
    if (groupRef.current) {
      groupRef.current.rotation.y = t * 0.1;
      groupRef.current.rotation.z = Math.sin(t * 0.2) * 0.1;
    }
    if (ringRef1.current) {
      ringRef1.current.rotation.x = t * 0.3;
      ringRef1.current.rotation.y = t * 0.2;
    }
    if (ringRef2.current) {
      ringRef2.current.rotation.x = -t * 0.2;
      ringRef2.current.rotation.z = t * 0.1;
    }
    if (coreRef.current) {
      coreRef.current.rotation.y = -t * 0.5;
      coreRef.current.rotation.x = Math.sin(t) * 0.2;
    }
  });

  return (
    <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
      <group ref={groupRef} position={[-2, 0.5, 0]}>
        {/* Outer Metallic Ring */}
        <mesh ref={ringRef1} castShadow receiveShadow>
          <torusGeometry args={[3.2, 0.08, 16, 100]} />
          <meshStandardMaterial
            color={COLORS.primary}
            emissive={COLORS.primary}
            emissiveIntensity={1.5}
            toneMapped={false}
          />
        </mesh>

        {/* Inner Glass Ring */}
        <mesh ref={ringRef2} castShadow receiveShadow>
          <torusGeometry args={[2.5, 0.3, 16, 64]} />
          <MeshTransmissionMaterial
            backside
            backsideThickness={5}
            thickness={2}
            chromaticAberration={1}
            anisotropy={1}
            distortion={1}
            distortionScale={1}
            temporalDistortion={0.2}
            iridescence={1}
            iridescenceIOR={1}
            iridescenceThicknessRange={[0, 1400]}
            roughness={0.1}
            color={COLORS.glass}
          />
        </mesh>

        {/* Core Crystal */}
        <mesh ref={coreRef} castShadow>
          <icosahedronGeometry args={[1.2, 0]} />
          <meshPhysicalMaterial
            roughness={0}
            metalness={0.2}
            transmission={0.9}
            thickness={3}
            color={COLORS.accent}
            emissive={COLORS.accent}
            emissiveIntensity={0.2}
          />
        </mesh>

        {/* Decorative Particles around core */}
        {Array.from({ length: 12 }).map((_, i) => (
          <mesh
            key={i}
            position={[
              Math.sin(i) * 2,
              Math.cos(i) * 2,
              Math.sin(i * 3) * 2
            ]}
          >
            <sphereGeometry args={[0.05, 16, 16]} />
            <meshBasicMaterial color={COLORS.primary} />
          </mesh>
        ))}
      </group>
    </Float>
  );
};

export default HeroSculpture;

import React, { useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text, Html, Float } from '@react-three/drei';
import * as THREE from 'three';
import { COLORS } from '../constants';
import { Project } from '../types';

interface ProjectCardProps {
  project: Project;
  position: [number, number, number];
  rotation: [number, number, number];
  onClick: (project: Project) => void;
}

const ProjectCard: React.FC<ProjectCardProps> = ({ project, position, rotation, onClick }) => {
  const meshRef = useRef<THREE.Group>(null);
  const [hovered, setHovered] = useState(false);

  useFrame((state) => {
    if (meshRef.current) {
      // Subtle float is handled by parent Float component, but we add scale on hover
      const targetScale = hovered ? 1.1 : 1;
      meshRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.1);
    }
  });

  // Mini Visualizations
  const renderViz = () => {
    if (project.type === 'bar') {
      return (
        <group position={[0, 0, 0.1]}>
          {[-1, -0.5, 0, 0.5, 1].map((x, i) => (
            <mesh key={i} position={[x * 0.8, -0.5 + (Math.sin(i * 10) + 1) * 0.25, 0]}>
              <boxGeometry args={[0.3, 1 + Math.sin(i * 20) * 0.8, 0.1]} />
              <meshStandardMaterial color={COLORS.primary} emissive={COLORS.primary} emissiveIntensity={0.5} />
            </mesh>
          ))}
        </group>
      );
    }
    if (project.type === 'cloud') {
       return (
        <points position={[0, 0, 0.1]}>
            <sphereGeometry args={[1, 16, 16]} />
            <pointsMaterial size={0.05} color={COLORS.accent} />
        </points>
       )
    }
    if (project.type === 'heatmap') {
        return (
            <group position={[0,0,0.1]}>
                 {Array.from({ length: 9 }).map((_, i) => {
                     const x = (i % 3) - 1;
                     const y = Math.floor(i / 3) - 1;
                     return (
                         <mesh key={i} position={[x * 0.7, y * 0.7, 0]}>
                             <boxGeometry args={[0.6, 0.6, 0.05]} />
                             <meshStandardMaterial
                                color={Math.random() > 0.5 ? COLORS.primary : COLORS.accent}
                                transparent opacity={0.6}
                             />
                         </mesh>
                     )
                 })}
            </group>
        )
    }
    return null;
  };

  return (
    <Float speed={2} rotationIntensity={0.2} floatIntensity={0.5}>
      <group
        ref={meshRef}
        position={position}
        rotation={rotation}
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
        onClick={() => onClick(project)}
      >
        {/* Card Glass Background */}
        <mesh>
          <boxGeometry args={[3, 4, 0.2]} />
          <meshPhysicalMaterial
            color="#111827"
            metalness={0.8}
            roughness={0.2}
            transparent
            opacity={0.8}
            side={THREE.DoubleSide}
          />
        </mesh>

        {/* Border Glow */}
        <mesh position={[0, 0, -0.05]}>
           <boxGeometry args={[3.05, 4.05, 0.15]} />
           <meshBasicMaterial color={hovered ? COLORS.accent : COLORS.primary} transparent opacity={0.3} />
        </mesh>

        {/* Content */}
        <group position={[0, 0.5, 0.15]}>
            {renderViz()}
        </group>

        {/* Text Overlay (World Space) */}
        <Text
            position={[0, -1.2, 0.12]}
            fontSize={0.2}
            color="white"
            anchorX="center"
            anchorY="middle"
            font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyfAZ9hjp-Ek-_EeA.woff"
        >
            {project.title}
        </Text>
        <Text
            position={[0, -1.5, 0.12]}
            fontSize={0.12}
            color={COLORS.primary}
            anchorX="center"
            anchorY="middle"
        >
            {project.category.toUpperCase()}
        </Text>

      </group>
    </Float>
  );
};

export default ProjectCard;

import React, { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { Environment, MeshReflectorMaterial, Stars, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';
import HeroSculpture from './HeroSculpture';
import ProjectCard from './ProjectCard';
import { PROJECTS, SCENE_CONFIG, COLORS } from '../constants';
import { Project } from '../types';

interface SceneProps {
  onProjectSelect: (project: Project) => void;
}

const Scene: React.FC<SceneProps> = ({ onProjectSelect }) => {
  return (
    <Canvas
      dpr={[1, 2]}
      camera={{ position: [0, 2, 12], fov: 35 }}
      gl={{ antialias: true, toneMapping: THREE.ACESFilmicToneMapping, toneMappingExposure: 1.2 }}
    >
      <fog attach="fog" args={[SCENE_CONFIG.fogColor, SCENE_CONFIG.fogNear, SCENE_CONFIG.fogFar]} />

      <Suspense fallback={null}>
        <Environment preset="city" />
        <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

        {/* Lights */}
        <ambientLight intensity={0.2} color={COLORS.background} />
        <spotLight
          position={[10, 10, 10]}
          angle={0.15}
          penumbra={1}
          intensity={1000}
          color={COLORS.primary}
          castShadow
        />
        <pointLight position={[-10, -10, -10]} intensity={500} color={COLORS.accent} />

        {/* Hero Object */}
        <HeroSculpture />

        {/* Project Cards */}
        <group position={[3, 0, 0]}>
           {PROJECTS.map((project, index) => {
               // Position calculation for a slight arc
               const x = index * 2.5; 
               const z = index * -1;
               return (
                   <ProjectCard 
                        key={project.id} 
                        project={project} 
                        position={[x, 0, z]} 
                        rotation={[0, -0.3, 0]}
                        onClick={onProjectSelect}
                    />
               );
           })}
        </group>

        {/* Reflective Floor */}
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -2.5, 0]}>
          <planeGeometry args={[50, 50]} />
          <MeshReflectorMaterial
            blur={[300, 100]}
            resolution={2048}
            mixBlur={1}
            mixStrength={80}
            roughness={0.5}
            depthScale={1.2}
            minDepthThreshold={0.4}
            maxDepthThreshold={1.4}
            color="#050505"
            metalness={0.5}
            mirror={0}
          />
        </mesh>

        <ContactShadows resolution={1024} scale={50} blur={2} opacity={0.5} far={10} color="#000000" />
      </Suspense>
    </Canvas>
  );
};

export default Scene;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Cpu } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import { COLORS } from '../constants';

const AIChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '0',
      role: 'model',
      text: "Greetings. I am AURA, the holographic assistant for this portfolio. How may I assist you today?",
      timestamp: Date.now(),
    },
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    // Prepare history for API
    const history = messages.map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    // Add current user message to history effectively for the call
    history.push({ role: 'user', parts: [{ text: userMsg.text }] });

    try {
      const responseText = await sendMessageToGemini(history, userMsg.text);
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
      };
      setMessages((prev) => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end pointer-events-auto">
      {/* Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`group flex items-center justify-center w-14 h-14 rounded-full backdrop-blur-md border border-[${COLORS.primary}] shadow-[0_0_15px_${COLORS.primary}] transition-all duration-300 hover:scale-110`}
        style={{
            backgroundColor: 'rgba(5, 10, 20, 0.7)',
            borderColor: COLORS.primary
        }}
      >
        {isOpen ? (
          <X className="w-6 h-6 text-white" />
        ) : (
          <MessageCircle className="w-6 h-6 text-[#00f3ff]" />
        )}
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="mb-4 w-80 sm:w-96 rounded-2xl overflow-hidden border border-white/10 backdrop-blur-xl shadow-2xl flex flex-col animate-in slide-in-from-bottom-5 fade-in duration-300"
            style={{ 
                height: '500px', 
                backgroundColor: 'rgba(5, 10, 20, 0.85)',
                boxShadow: `0 0 30px -5px ${COLORS.darkGlass}`
            }}
        >
          {/* Header */}
          <div className="p-4 border-b border-white/10 flex items-center justify-between bg-white/5">
            <div className="flex items-center gap-2">
              <Cpu className="w-5 h-5 text-[#00f3ff]" />
              <span className="font-bold tracking-wider text-sm text-white">AURA v2.5</span>
            </div>
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              <span className="text-xs text-white/50">ONLINE</span>
            </div>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                    msg.role === 'user'
                      ? 'bg-[#00f3ff]/20 text-white rounded-tr-sm border border-[#00f3ff]/30'
                      : 'bg-white/10 text-gray-200 rounded-tl-sm border border-white/5'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
               <div className="flex justify-start">
                   <div className="bg-white/10 p-3 rounded-2xl rounded-tl-sm flex gap-1 items-center">
                       <div className="w-1.5 h-1.5 bg-[#00f3ff] rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                       <div className="w-1.5 h-1.5 bg-[#00f3ff] rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                       <div className="w-1.5 h-1.5 bg-[#00f3ff] rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                   </div>
               </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 border-t border-white/10 bg-white/5">
            <div className="relative flex items-center">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask about projects..."
                className="w-full bg-black/30 border border-white/10 rounded-xl py-3 pl-4 pr-12 text-sm text-white focus:outline-none focus:border-[#00f3ff]/50 transition-colors placeholder:text-white/20"
              />
              <button
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="absolute right-2 p-2 hover:bg-white/10 rounded-lg transition-colors disabled:opacity-50"
              >
                <Send className="w-4 h-4 text-[#00f3ff]" />
              </button>
            </div>
            <div className="text-[10px] text-center mt-2 text-white/20">
                Powered by Google Gemini 
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIChat;

