              <button className="group w-full py-4 bg-white text-black font-bold text-sm tracking-widest uppercase flex items-center justify-center gap-2 hover:bg-[#00f3ff] transition-colors rounded-sm">
                View Case Study <ExternalLink className="w-4 h-4" />
