export const sendMessageToGemini = async (history: { role: string; parts: [{ text: string }] }[], message: string): Promise<string> => {
  try {
    if (!process.env.API_KEY) {
      return "I'm sorry, my neural link (API Key) is disconnected. Please check the configuration.";
    }

    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history,
    });

    const result = await chat.sendMessage({ message });
    return result.text || "I processed that, but produced no audio/text output.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I encountered a processing error in my logic core. Please try again.";
  }
};

