  onProjectSelect: (project: Project) => void;
}

// Camera Rig for Mouse Parallax
const CameraRig = () => {
  useFrame((state) => {
    // Smoothly lerp camera position based on mouse pointer
    // state.pointer.x/y are normalized coordinates (-1 to 1)
    state.camera.position.lerp(
      new THREE.Vector3(
        state.pointer.x * 2,   // Move slightly on X axis
        2 + state.pointer.y * 1, // Move slightly on Y axis (relative to base height of 2)
        12                      // Fixed Z depth
      ),
      0.05 // Smoothing factor
    );
    state.camera.lookAt(0, 0, 0);
  });
  return null;
};

