import React, { useState, useRef } from 'react';

interface GlitchTextProps {
  text: string;
  className?: string;
  highlightColor?: string;
}

const CHARS = '!@#$%^&*()_+-=[]{}|;:,.<>?/ABCDEFGHIJKLMNOPQRSTUVWXYZ';

const GlitchText: React.FC<GlitchTextProps> = ({ text, className = '', highlightColor }) => {
  const [displayText, setDisplayText] = useState(text);
  const intervalRef = useRef<number | null>(null);

  const startGlitch = () => {
    let iteration = 0;
    if (intervalRef.current) clearInterval(intervalRef.current);

    intervalRef.current = window.setInterval(() => {
      setDisplayText(
        text
          .split('')
          .map((char, index) => {
            if (index < iteration) return text[index];
            return CHARS[Math.floor(Math.random() * CHARS.length)];
          })
          .join('')
      );

      if (iteration >= text.length) {
        if (intervalRef.current) clearInterval(intervalRef.current);
      }

      iteration += 1 / 2; // Glitch speed
    }, 30);
  };

  return (
    <span 
      className={`relative inline-block cursor-default ${className}`}
      onMouseEnter={startGlitch}
      onTouchStart={startGlitch}
    >
      {displayText}
    </span>
  );
};

export default GlitchText;

import React, { useEffect, useState } from 'react';

const TERMINAL_LINES = [
  "INITIALIZING CORE SYSTEMS...",
  "LOADING NEURAL TEXTURES...",
  "CONNECTING TO API GATEWAY...",
  "CALIBRATING 3D VIEWPORT...",
  "ACCESS GRANTED."
];

const Preloader: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [lines, setLines] = useState<string[]>([]);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    // Progress bar animation
    const progressInterval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(progressInterval);
          return 100;
        }
        return prev + 4;
      });
    }, 50);

    // Lines animation
    let lineIndex = 0;
    const lineInterval = setInterval(() => {
      if (lineIndex < TERMINAL_LINES.length) {
        setLines(prev => [...prev, TERMINAL_LINES[lineIndex]]);
        lineIndex++;
      } else {
        clearInterval(lineInterval);
      }
    }, 350);

    // Completion delay
    const timeout = setTimeout(() => {
      onComplete();
    }, 2500);

    return () => {
      clearInterval(progressInterval);
      clearInterval(lineInterval);
      clearTimeout(timeout);
    };
  }, [onComplete]);

  return (
    <div className="fixed inset-0 z-[100] bg-[#020408] flex flex-col items-center justify-center font-mono text-[#00f3ff] p-8">
       <div className="w-full max-w-md space-y-6">
